class Solution:
    def getKth(self, lo: int, hi: int, k: int) -> int:
        def power(x):
            steps = 0
            while x != 1:
                if x % 2 == 0:
                    x //= 2
                else:
                    x = 3 * x + 1
                steps += 1
            return steps

        powers = {}
        for i in range(lo, hi + 1):
            powers[i] = power(i)

        sorted_nums = sorted(powers, key=lambda x: (powers[x], x))
        return sorted_nums[k - 1]
```

